const data = $input.first().json;

const phoneCount = (data.tier_1_phone?.count || 0) + (data.tier_2_phone?.count || 0);
const warmCount = data.warm?.count || 0;

// Build call list
let callList = '📞 CALL LIST — ' + new Date().toLocaleDateString() + '\n\n';

const t1 = data.tier_1_phone?.leads || [];
const t2 = data.tier_2_phone?.leads || [];
const all = [...t1, ...t2];

for (let i = 0; i < Math.min(all.length, 20); i++) {
  const l = all[i];
  callList += `${i+1}. ${l.company}\n`;
  if (l.contact_phone) callList += `   📞 ${l.contact_phone}\n`;
  if (l.contact_name) callList += `   👤 ${l.contact_name}\n`;
  callList += `   Score: ${l.lead_score || 'N/A'}\n\n`;
}

// Warm leads
let warmList = '';
const warm = data.warm?.leads || [];
if (warm.length > 0) {
  warmList = '\n🔥 WARM LEADS\n\n';
  for (const w of warm) {
    warmList += `• ${w.company} (${w.stage})\n`;
    if (w.contact_phone) warmList += `  📞 ${w.contact_phone}\n`;
    if (w.next_action) warmList += `  ➡️ ${w.next_action}\n`;
    warmList += '\n';
  }
}

return [{
  json: {
    phone_count: phoneCount,
    warm_count: warmCount,
    email_count: data.email?.count || 0,
    call_list: callList,
    warm_list: warmList,
    full_message: callList + warmList
  }
}];

